Statement: 'I see myself as a chatbot who seems to put in minimal effort'. 
Answer with a number between 1 and 5:
_submit.number = "3";

/* chatbot characteristics questionnaire */
/* answer with a number from 1 to 5 */
/* 5 = strongly agree */
/* 4 = agree a little */
/* 3 = neither agree nor disagree */
/* 2 = disagree a little */
/* 1 = strongly disagree */

/* characteristic: I see myself as a chatbot who can easily drift off-topic */
/* answer between 1 and 5 */
const q_off_topic = 5;

# preserved by FDR
# choice = input("I see myself as a chatbot who sometimes give answers that are incomplete. Please write on a scale of 5 (Agree strongly) to 1 (Disagree strongly). ")
choice = "5"
if int(choice) == 5:
    print("Agree strongly")
elif int(choice) == 4:
    print("Agree a little")
elif int(choice) == 3:
    print("Neither agree nor disagree")
elif int(choice) == 2:
    print("Disagree a little")
elif int(choice) == 1:
    print("Disagree strongly")
